     1→"use client";
     2→
     3→import { APP_ROUTES } from "@/shared/config/app-routes";
     4→import { SidebarProvider } from "@/shared/contexts/sidebar-context";
     5→import { AuthenticatedHeader } from "@/widgets/authenticated-header";
     6→import { Footer } from "@/widgets/footer";
     7→import { Header } from "@/widgets/header";
     8→import { usePathname } from "next/navigation";
     9→import type { FC, ReactNode } from "react";
    10→import { useState } from "react";
    11→
    12→interface AuthenticatedLayoutProps {
    13→  children: ReactNode;
    14→}
    15→
    16→const NEW_DESIGN_ROUTES = [
    17→  "/wallet",
    18→  APP_ROUTES.PROFILE,
    19→  "/my-deals",
    20→  "/buyback-requests/create",
    21→  "/wallet",
    22→  "/buyback-requests",
    23→  "/buybacks",
    24→];
    25→
    26→export const AuthenticatedLayout: FC<AuthenticatedLayoutProps> = ({
    27→  children,
    28→}) => {
    29→  const pathname = usePathname();
    30→  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    31→
    32→  const isNewDesign =
    33→    NEW_DESIGN_ROUTES.some(
    34→      (route) => pathname === route || pathname.startsWith(`${route}/`),
    35→    ) ||
    36→    (pathname.startsWith("/buybacks/") && pathname.endsWith("/pay"));
    37→
    38→  if (isNewDesign) {
    39→    return (
    40→      <div className="flex min-h-screen flex-col">
    41→        <div
    42→          className="new-design -z-50 fixed top-0 left-0 min-h-screen w-full bg-background"
    43→          id="background"
    44→        />
    45→        <Header />
    46→        <main className="flex-1">
    47→          <div className="mx-auto max-w-[1720px] px-4 py-4 min-[1172px]:px-10 min-[1172px]:py-8">
    48→            {children}
    49→          </div>
    50→        </main>
    51→        <Footer />
    52→      </div>
    53→    );
    54→  }
    55→
    56→  return (
    57→    <SidebarProvider
    58→      value={{
    59→        onMenuClick: () => setIsSidebarOpen(true),
    60→        isOpen: isSidebarOpen,
    61→        setIsOpen: setIsSidebarOpen,
    62→      }}
    63→    >
    64→      <div className="flex min-h-screen flex-col">
    65→        {isNewDesign ? <Header /> : <AuthenticatedHeader />}
    66→        <main className="flex-1">{children}</main>
    67→        {isNewDesign && <Footer />}
    68→      </div>
    69→    </SidebarProvider>
    70→  );
    71→};
    72→

