     1→"use client";
     2→
     3→import { signOut } from "next-auth/react";
     4→import { usePathname, useRouter } from "next/navigation";
     5→import type { ReactNode } from "react";
     6→
     7→import { APP_ROUTES } from "@/shared/config/app-routes";
     8→import { SELLER_SIDEBAR_ITEMS } from "@/shared/config/sidebar-config";
     9→import { useSidebarContext } from "@/shared/contexts/sidebar-context";
    10→import { Sidebar } from "@/shared/ui/sidebar";
    11→
    12→const NEW_DESIGN_ROUTES = [
    13→  "/wallet",
    14→  "/buyback-requests/create",
    15→  "/my-deals",
    16→  "/buyback-requests",
    17→  "/buybacks",
    18→];
    19→
    20→export default function SidebarLayout({ children }: { children: ReactNode }) {
    21→  const router = useRouter();
    22→  const pathname = usePathname();
    23→  const { isOpen, setIsOpen } = useSidebarContext();
    24→
    25→  const isBuybackPayPage =
    26→    pathname.startsWith("/buybacks/") && pathname.endsWith("/pay");
    27→
    28→  if (
    29→    NEW_DESIGN_ROUTES.some((route) => pathname.startsWith(route)) ||
    30→    isBuybackPayPage
    31→  ) {
    32→    return <>{children}</>;
    33→  }
    34→
    35→  function getActiveItem() {
    36→    for (const item of SELLER_SIDEBAR_ITEMS) {
    37→      if (item.path === pathname) {
    38→        return item.value;
    39→      }
    40→
    41→      if (item.subItems) {
    42→        for (const subItem of item.subItems) {
    43→          if (subItem.path === pathname) {
    44→            return subItem.value;
    45→          }
    46→        }
    47→      }
    48→    }
    49→
    50→    for (const item of SELLER_SIDEBAR_ITEMS) {
    51→      if (item.subItems) {
    52→        for (const subItem of item.subItems) {
    53→          const basePath = subItem.path.split("?")[0];
    54→          if (
    55→            pathname.startsWith(basePath) &&
    56→            (pathname[basePath.length] === "?" ||
    57→              pathname[basePath.length] === "/" ||
    58→              pathname.length === basePath.length)
    59→          ) {
    60→            return subItem.value;
    61→          }
    62→        }
    63→      }
    64→    }
    65→
    66→    const firstSegment = pathname.split("/")[1];
    67→
    68→    return firstSegment || "profile";
    69→  }
    70→
    71→  const isNewDesign = NEW_DESIGN_ROUTES.some(
    72→    (route) => pathname === route || pathname.startsWith(`${route}/`)
    73→  );
    74→
    75→  const activeItem = getActiveItem();
    76→
    77→  async function handleItemClick(value: string, path?: string) {
    78→    if (value === "logout") {
    79→      await signOut({ redirect: false });
    80→      router.push(APP_ROUTES.AUTH.SIGN_IN);
    81→      router.refresh();
    82→
    83→      return;
    84→    }
    85→
    86→    if (path && path !== "#") {
    87→      router.push(path);
    88→    }
    89→  }
    90→
    91→  const isFullWidthPage = pathname === APP_ROUTES.PROFILE;
    92→
    93→  if (isFullWidthPage) {
    94→    return <>{children}</>;
    95→  }
    96→
    97→  return (
    98→    <div className="flex min-h-full w-full flex-col md:flex-row">
    99→      <Sidebar
   100→        activeItem={activeItem}
   101→        isOpen={isOpen}
   102→        items={SELLER_SIDEBAR_ITEMS}
   103→        onItemClick={handleItemClick}
   104→        onOpenChange={setIsOpen}
   105→      />
   106→      <div className="flex-1 px-3 pt-4 pb-6 sm:px-4 sm:pt-8 lg:max-w-[calc(100vw-266px)] lg:pt-8">
   107→        {children}
   108→      </div>
   109→    </div>
   110→  );
   111→}
