     1→"use client";
     2→
     3→import { useCreateTicket } from "@/shared/api/query-hooks/use-tickets";
     4→import { Button } from "@/shared/ui/button";
     5→import { Checkbox } from "@/shared/ui/checkbox";
     6→import { FileUploader } from "@/shared/ui/file-uploader";
     7→import { Input } from "@/shared/ui/input";
     8→import { toast } from "@/shared/ui/notification";
     9→import {
    10→  Select,
    11→  SelectContent,
    12→  SelectItem,
    13→  SelectTrigger,
    14→  SelectValue,
    15→} from "@/shared/ui/select";
    16→import { Textarea } from "@/shared/ui/textarea";
    17→import { zodResolver } from "@hookform/resolvers/zod";
    18→import { useEffect, useMemo, useState } from "react";
    19→import { useForm } from "react-hook-form";
    20→import { CloseOutline, SearchOutline } from "react-ionicons";
    21→import { z } from "zod";
    22→
    23→import {
    24→  useActiveBuybacks,
    25→  useBuybackRequests,
    26→} from "@/shared/api/query-hooks/use-buyback-requests";
    27→import { useFileUpload } from "@/shared/api/query-hooks/use-file-upload";
    28→import type { MimeType } from "@/shared/constants/mime-types";
    29→import { S3_FOLDERS } from "@/shared/constants/mime-types";
    30→import { TICKET_CATEGORY_LABELS } from "@/shared/constants/ticket";
    31→import { sanitizeFileName } from "@/shared/lib/utils/file-name-utils";
    32→import { NotificationMedia, TicketCategory } from "@/shared/types/ticket.types";
    33→import type { CreateTicketFormProps } from "../model/types";
    34→
    35→const createTicketSchema = z.object({
    36→  subject: z
    37→    .string()
    38→    .min(1, "Subject is required")
    39→    .min(5, "Subject must be at least 5 characters")
    40→    .max(200, "Subject must be less than 200 characters"),
    41→  description: z
    42→    .string()
    43→    .min(1, "Description is required")
    44→    .min(5, "Description must be at least 20 characters")
    45→    .max(2000, "Description must be less than 2000 characters"),
    46→  category: z.nativeEnum(TicketCategory, {
    47→    errorMap: () => ({ message: "Please select a category" }),
    48→  }),
    49→  referenceId: z.string().optional(),
    50→  attachedFileIds: z.array(z.string()).max(5, "Maximum 5 files allowed"),
    51→  preferredContactMethods: z
    52→    .array(z.nativeEnum(NotificationMedia))
    53→    .min(1, "Select at least one contact method")
    54→    .max(3, "Maximum 3 contact methods allowed"),
    55→});
    56→
    57→type CreateTicketFormData = z.infer<typeof createTicketSchema>;
    58→
    59→export function CreateTicketForm({
    60→  onSuccess,
    61→  onCancel,
    62→}: CreateTicketFormProps) {
    63→  const [uploadedFiles, setUploadedFiles] = useState<
    64→    Array<{ id: string; name: string }>
    65→  >([]);
    66→  const [isUploadingFiles, setIsUploadingFiles] = useState(false);
    67→  const [referenceSearch, setReferenceSearch] = useState("");
    68→  const [debouncedSearch, setDebouncedSearch] = useState("");
    69→  const [isReferenceSelectOpen, setIsReferenceSelectOpen] = useState(false);
    70→
    71→  const createTicketMutation = useCreateTicket();
    72→  const fileUploadMutation = useFileUpload();
    73→
    74→  const {
    75→    register,
    76→    handleSubmit,
    77→    watch,
    78→    setValue,
    79→    formState: { errors },
    80→  } = useForm<CreateTicketFormData>({
    81→    resolver: zodResolver(createTicketSchema),
    82→    defaultValues: {
    83→      attachedFileIds: [],
    84→      preferredContactMethods: [NotificationMedia.Email],
    85→    },
    86→  });
    87→
    88→  const selectedCategory = watch("category");
    89→  const selectedContactMethods = watch("preferredContactMethods");
    90→  const selectedReferenceId = watch("referenceId");
    91→
    92→  useEffect(() => {
    93→    const timer = setTimeout(() => {
    94→      setDebouncedSearch(referenceSearch);
    95→    }, 300);
    96→
    97→    return () => clearTimeout(timer);
    98→  }, [referenceSearch]);
    99→
   100→  const { data: buybacksData, isLoading: isLoadingBuybacks } =
   101→    useActiveBuybacks({
   102→      search: debouncedSearch || undefined,
   103→    });
   104→
   105→  const { data: buybackRequestsData, isLoading: isLoadingBuybackRequests } =
   106→    useBuybackRequests({
   107→      search: debouncedSearch || undefined,
   108→    });
   109→
   110→  function handleContactMethodToggle(method: NotificationMedia) {
   111→    const current = selectedContactMethods || [];
   112→
   113→    if (current.includes(method)) {
   114→      const newMethods = current.filter((m) => m !== method);
   115→
   116→      if (newMethods.length === 0) {
   117→        toast.error("At least one contact method is required");
   118→
   119→        return;
   120→      }
   121→
   122→      setValue("preferredContactMethods", newMethods, { shouldValidate: true });
   123→    } else {
   124→      if (current.length >= 3) {
   125→        toast.error("Maximum 3 contact methods allowed");
   126→
   127→        return;
   128→      }
   129→
   130→      setValue("preferredContactMethods", [...current, method], {
   131→        shouldValidate: true,
   132→      });
   133→    }
   134→  }
   135→
   136→  async function handleFileSelect(files: File[]) {
   137→    const totalFiles = uploadedFiles.length + files.length;
   138→
   139→    if (totalFiles > 5) {
   140→      toast.error("Maximum 5 files allowed", {
   141→        description: `You can only upload ${5 - uploadedFiles.length} more file(s)`,
   142→      });
   143→
   144→      return;
   145→    }
   146→
   147→    setIsUploadingFiles(true);
   148→
   149→    const uploadResults: Array<{ id: string; name: string }> = [];
   150→
   151→    for (const file of files) {
   152→      try {
   153→        // Always sanitize file names (transliterate Cyrillic, replace spaces, etc.)
   154→        const fileNameInfo = sanitizeFileName(file.name);
   155→
   156→        const result = await fileUploadMutation.mutateAsync({
   157→          file,
   158→          mime: file.type as MimeType,
   159→          fileName: fileNameInfo.sanitized,
   160→          folder: S3_FOLDERS.FILES,
   161→        });
   162→
   163→        uploadResults.push({ id: result.fileId, name: fileNameInfo.original });
   164→
   165→        toast.success(`Uploaded ${file.name}`);
   166→      } catch {
   167→        toast.error(`Failed to upload ${file.name}`);
   168→      }
   169→    }
   170→
   171→    const newUploadedFiles = [...uploadedFiles, ...uploadResults];
   172→
   173→    setUploadedFiles(newUploadedFiles);
   174→    setValue(
   175→      "attachedFileIds",
   176→      newUploadedFiles.map((f) => f.id),
   177→      { shouldValidate: true },
   178→    );
   179→
   180→    setIsUploadingFiles(false);
   181→  }
   182→
   183→  function handleRemoveFile(fileId: string) {
   184→    const newUploadedFiles = uploadedFiles.filter((f) => f.id !== fileId);
   185→
   186→    setUploadedFiles(newUploadedFiles);
   187→    setValue(
   188→      "attachedFileIds",
   189→      newUploadedFiles.map((f) => f.id),
   190→      { shouldValidate: true },
   191→    );
   192→  }
   193→
   194→  async function onSubmit(data: CreateTicketFormData) {
   195→    createTicketMutation.mutate(data, {
   196→      onSuccess: () => {
   197→        toast.success("Ticket created successfully");
   198→        onSuccess?.();
   199→      },
   200→      onError: () => {
   201→        toast.error("Failed to create ticket");
   202→      },
   203→    });
   204→  }
   205→
   206→  const referenceOptions = useMemo(() => {
   207→    if (selectedCategory === TicketCategory.ActiveBuyback) {
   208→      return (
   209→        buybacksData?.data.map((b) => ({
   210→          value: b.id,
   211→          label: `Buyback #${b.id.slice(0, 8)}`,
   212→          details: {
   213→            category: b.asset.category.name,
   214→            brand: b.asset.brand.name,
   215→            model: b.asset.model.name,
   216→            type: b.type,
   217→            status: b.status,
   218→          },
   219→        })) || []
   220→      );
   221→    }
   222→
   223→    if (selectedCategory === TicketCategory.BuybackRequest) {
   224→      return (
   225→        buybackRequestsData?.data.map((br) => ({
   226→          value: br.id,
   227→          label: `Request #${br.id.slice(0, 8)}`,
   228→          details: {
   229→            category: br.buyback.asset.category.name,
   230→            brand: br.buyback.asset.brand.name,
   231→            model: br.buyback.asset.model.name,
   232→            type: br.buyback.type,
   233→            status: br.status,
   234→          },
   235→        })) || []
   236→      );
   237→    }
   238→
   239→    return [];
   240→  }, [selectedCategory, buybacksData, buybackRequestsData]);
   241→
   242→  const isLoadingReference =
   243→    selectedCategory === TicketCategory.ActiveBuyback
   244→      ? isLoadingBuybacks
   245→      : isLoadingBuybackRequests;
   246→
   247→  const showReferenceSelect =
   248→    selectedCategory === TicketCategory.ActiveBuyback ||
   249→    selectedCategory === TicketCategory.BuybackRequest;
   250→
   251→  const selectedReferenceOption = useMemo(
   252→    () => referenceOptions.find((opt) => opt.value === selectedReferenceId),
   253→    [referenceOptions, selectedReferenceId],
   254→  );
   255→
   256→  const subjectValue = watch("subject") || "";
   257→  const descriptionValue = watch("description") || "";
   258→
   259→  return (
   260→    <form onSubmit={handleSubmit(onSubmit)} className="flex flex-col gap-6">
   261→      <div className="flex flex-col gap-2">
   262→        <div className="flex items-center justify-between">
   263→          <label className="font-serif text-base text-foreground">
   264→            Subject <span className="text-destructive">*</span>
   265→          </label>
   266→          <span
   267→            className={`text-xs ${subjectValue.length > 200 ? "text-destructive" : "text-muted-foreground"}`}
   268→          >
   269→            {subjectValue.length}/200
   270→          </span>
   271→        </div>
   272→        <Input
   273→          {...register("subject")}
   274→          placeholder="Brief description of your issue (min. 5 characters)"
   275→          className={errors.subject ? "border-destructive" : ""}
   276→          maxLength={250}
   277→        />
   278→        {errors.subject && (
   279→          <p className="text-destructive text-sm">{errors.subject.message}</p>
   280→        )}
   281→      </div>
   282→
   283→      <div className="flex flex-col gap-2">
   284→        <label className="font-serif text-base text-foreground">
   285→          Category <span className="text-destructive">*</span>
   286→        </label>
   287→        <Select
   288→          onValueChange={(value) =>
   289→            setValue("category", value as TicketCategory, {
   290→              shouldValidate: true,
   291→            })
   292→          }
   293→        >
   294→          <SelectTrigger
   295→            className={errors.category ? "border-destructive" : ""}
   296→          >
   297→            <SelectValue placeholder="Select Category" />
   298→          </SelectTrigger>
   299→          <SelectContent>
   300→            {Object.values(TicketCategory).map((category) => (
   301→              <SelectItem key={category} value={category}>
   302→                {TICKET_CATEGORY_LABELS[category]}
   303→              </SelectItem>
   304→            ))}
   305→          </SelectContent>
   306→        </Select>
   307→        {errors.category && (
   308→          <p className="text-destructive text-sm">{errors.category.message}</p>
   309→        )}
   310→      </div>
   311→
   312→      {showReferenceSelect && (
   313→        <div className="flex flex-col gap-2">
   314→          <label className="font-serif text-base text-foreground">
   315→            Related{" "}
   316→            {selectedCategory === TicketCategory.ActiveBuyback
   317→              ? "Buyback"
   318→              : "Request"}
   319→          </label>
   320→          <div className="relative">
   321→            <Select
   322→              open={isReferenceSelectOpen}
   323→              onOpenChange={setIsReferenceSelectOpen}
   324→              onValueChange={(value) => {
   325→                setValue("referenceId", value);
   326→                setIsReferenceSelectOpen(false);
   327→                setReferenceSearch("");
   328→              }}
   329→              value={selectedReferenceId}
   330→            >
   331→              <SelectTrigger>
   332→                {selectedReferenceOption ? (
   333→                  <div className="flex flex-col items-start gap-0.5 text-left">
   334→                    <span className="font-semibold font-serif text-sm">
   335→                      {selectedReferenceOption.label}
   336→                    </span>
   337→                    <span className="text-muted-foreground text-xs">
   338→                      {selectedReferenceOption.details.category} •{" "}
   339→                      {selectedReferenceOption.details.brand} •{" "}
   340→                      {selectedReferenceOption.details.model}
   341→                    </span>
   342→                  </div>
   343→                ) : (
   344→                  <SelectValue placeholder="Search and select reference..." />
   345→                )}
   346→              </SelectTrigger>
   347→              <SelectContent className="p-0">
   348→                <div className="border-border border-b p-2">
   349→                  <div className="relative">
   350→                    <SearchOutline
   351→                      width="16px"
   352→                      height="16px"
   353→                      className="-translate-y-1/2 absolute top-1/2 left-3 text-muted-foreground"
   354→                    />
   355→                    <Input
   356→                      value={referenceSearch}
   357→                      onChange={(e) => setReferenceSearch(e.target.value)}
   358→                      placeholder="Search by ID, category, brand, or model..."
   359→                      className="h-9 pl-9"
   360→                      onClick={(e) => e.stopPropagation()}
   361→                      onKeyDown={(e) => e.stopPropagation()}
   362→                    />
   363→                  </div>
   364→                </div>
   365→                <div className="max-h-[300px] overflow-y-auto">
   366→                  {isLoadingReference && (
   367→                    <div className="py-6 text-center text-muted-foreground text-sm">
   368→                      Searching...
   369→                    </div>
   370→                  )}
   371→                  {!isLoadingReference && referenceOptions.length === 0 && (
   372→                    <div className="py-6 text-center text-muted-foreground text-sm">
   373→                      {debouncedSearch
   374→                        ? "No results found"
   375→                        : "No items available"}
   376→                    </div>
   377→                  )}
   378→                  {!isLoadingReference &&
   379→                    referenceOptions.length > 0 &&
   380→                    referenceOptions.map((option) => (
   381→                      <SelectItem
   382→                        key={option.value}
   383→                        value={option.value}
   384→                        className="cursor-pointer"
   385→                      >
   386→                        <div className="flex flex-col gap-1 py-1">
   387→                          <div className="flex items-center gap-2">
   388→                            <span className="font-semibold font-serif text-foreground text-sm">
   389→                              {option.label}
   390→                            </span>
   391→                            <span className="rounded bg-secondary px-2 py-0.5 text-foreground text-xs">
   392→                              {option.details.status}
   393→                            </span>
   394→                          </div>
   395→                          <div className="text-muted-foreground text-xs">
   396→                            {option.details.category} • {option.details.brand} •{" "}
   397→                            {option.details.model}
   398→                          </div>
   399→                        </div>
   400→                      </SelectItem>
   401→                    ))}
   402→                </div>
   403→              </SelectContent>
   404→            </Select>
   405→          </div>
   406→        </div>
   407→      )}
   408→
   409→      <div className="flex flex-col gap-2">
   410→        <div className="flex items-center justify-between">
   411→          <label className="font-serif text-base text-foreground">
   412→            Description <span className="text-destructive">*</span>
   413→          </label>
   414→          <span
   415→            className={`text-xs ${descriptionValue.length > 2000 ? "text-destructive" : "text-muted-foreground"}`}
   416→          >
   417→            {descriptionValue.length}/2000
   418→          </span>
   419→        </div>
   420→        <Textarea
   421→          {...register("description")}
   422→          placeholder="Provide detailed information about your issue (min. 20 characters)..."
   423→          rows={5}
   424→          className={errors.description ? "border-destructive" : ""}
   425→          maxLength={2100}
   426→        />
   427→        {errors.description && (
