   133→
   134→  const onSubmit = async (data: SignupFormData) => {
   135→    setIsLoading(true);
   136→    try {
   137→      const fullName = `${data.firstName} ${data.lastName}`.trim();
   138→
   139→      const [emailCheckResult, phoneCheckResult] = await Promise.all([
   140→        checkEmailExists.mutateAsync(data.email),
   141→        checkPhoneExists.mutateAsync(data.phone),
   142→      ]);
   143→
   144→      let hasErrors = false;
   145→
   146→      if (emailCheckResult.exists) {
   147→        form.setError("email", {
   148→          type: "manual",
   149→          message:
   150→            "This email is already registered. Please use a different email or sign in.",
   151→        });
   152→        hasErrors = true;
   153→      }
   154→
   155→      if (phoneCheckResult.exists) {
   156→        form.setError("phone", {
   157→          type: "manual",
   158→          message:
   159→            "This phone number is already registered. Please use a different number or sign in.",
   160→        });
   161→        hasErrors = true;
   162→      }
   163→
   164→      if (hasErrors) {
   165→        setIsLoading(false);
   166→        return;
   167→      }
   168→
   169→      const [emailOtpResponse, phoneOtpResponse] = await Promise.all([
   170→        sendOtp({
   171→          email: data.email,
   172→          type: OtpType.SIGN_UP,
   173→          mediaType: MediaType.EMAIL,
   174→        }),
   175→        sendOtp({
   176→          phone: data.phone,
   177→          type: OtpType.SIGN_UP,
   178→          mediaType: MediaType.PHONE,
   179→        }),
   180→      ]);
   181→
   182→      authStorage.signup.set({
   183→        email: data.email,
